import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  ScrollView,
  TouchableOpacity,
  StyleSheet,
  Image,
  Alert,
  Switch,
  Dimensions,
  SafeAreaView,
  StatusBar,
  Platform,
} from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons, MaterialIcons } from '@expo/vector-icons';
import AsyncStorage from '@react-native-async-storage/async-storage';
import Toast from 'react-native-toast-message';
import CustomToast from '../components/CustomToast';
import { useTheme } from '../context/ThemeContext';
import API_BASE from '../constants/api';

const { width, height } = Dimensions.get('window');

const UserProfile = ({ navigation }) => {
  const { theme, isDark, toggleTheme } = useTheme();
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [notifications, setNotifications] = useState(true);
  const [emailUpdates, setEmailUpdates] = useState(true);

  useEffect(() => {
    loadUserData();
  }, []);

  const loadUserData = async () => {
    try {
      const userData = await AsyncStorage.getItem('userData');
      if (userData) {
        const parsed = JSON.parse(userData);
        setUser(parsed);
        // Fetch real order stats from backend
        if (parsed?._id || parsed?.id) {
          fetchOrderStats(parsed._id || parsed.id, parsed);
        }
      } else {
        setUser({
          name: 'John Doe',
          email: 'john.doe@example.com',
          phone: '+256 700 123 456',
          avatar: null,
          joinDate: '2024-01-15',
          totalOrders: 0,
          totalSpent: 0,
        });
      }
    } catch (error) {
      console.error('Error loading user data:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchOrderStats = async (userId, baseUser) => {
    try {
      const res = await fetch(`${API_BASE}/orders?userId=${userId}`);
      const data = await res.json();
      const orders = Array.isArray(data) ? data : (data.orders || []);
      const totalOrders = orders.length;
      const totalSpent = orders.reduce((sum, o) => {
        const amount = (o.subtotal || 0) + (o.deliveryFee || 0);
        return sum + amount;
      }, 0);
      setUser(prev => ({ ...prev, totalOrders, totalSpent }));
    } catch (e) {
      console.error('Error fetching order stats:', e);
    }
  };

  const handleLogout = async () => {
    Alert.alert(
      'Logout',
      'Are you sure you want to logout?',
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Logout',
          style: 'destructive',
          onPress: async () => {
            try {
              await AsyncStorage.multiRemove(['userToken', 'userData']);
              
              Toast.show({
                type: 'success',
                text1: 'Logged Out',
                text2: 'You have been successfully logged out',
                position: 'top',
                visibilityTime: 2000,
              });

              setTimeout(() => {
                navigation.navigate('home');
              }, 1000);
            } catch (error) {
              console.error('Logout error:', error);
              Toast.show({
                type: 'error',
                text1: 'Logout Failed',
                text2: 'Something went wrong. Please try again.',
                position: 'top',
                visibilityTime: 3000,
              });
            }
          }
        }
      ]
    );
  };

  const menuItems = [
    {
      id: 1,
      title: 'My Orders',
      subtitle: 'Track your orders and history',
      icon: 'receipt-outline',
      color: '#3498db',
      onPress: () => navigation.navigate('UserOrders')
    },
    {
      id: 2,
      title: 'Wishlist',
      subtitle: 'Your saved items',
      icon: 'heart-outline',
      color: '#e74c3c',
      onPress: () => navigation.navigate('Wishlist')
    },
    {
      id: 3,
      title: 'My Cart',
      subtitle: 'View your shopping cart',
      icon: 'cart-outline',
      color: '#f39c12',
      onPress: () => navigation.navigate('Cart')
    },
    {
      id: 4,
      title: 'Addresses',
      subtitle: 'Manage delivery addresses',
      icon: 'location-outline',
      color: '#27ae60',
      onPress: () => navigation.navigate('UserDeliverySettings')
    },
    {
      id: 5,
      title: 'Payment Methods',
      subtitle: 'Cards and payment options',
      icon: 'card-outline',
      color: '#9b59b6',
      onPress: () => Toast.show({
        type: 'info',
        text1: 'Coming Soon!',
        text2: 'Payment methods will be available soon',
        position: 'top',
        visibilityTime: 2000,
      })
    },
    {
      id: 6,
      title: 'Help & Support',
      subtitle: 'Get help and contact us',
      icon: 'help-circle-outline',
      color: '#34495e',
      onPress: () => navigation.navigate('HelpSupport')
    },
    {
      id: 7,
      title: 'Continue as Special Guest',
      subtitle: 'Browse without an account',
      icon: 'person-outline',
      color: '#16a085',
      onPress: () => {
        // Show confirmation before navigating to Special Guest
        Alert.alert(
          'Continue as Special Guest',
          'This will take you to the special guest section. You may need to verify your credentials.',
          [
            { text: 'Cancel', style: 'cancel' },
            { 
              text: 'Continue', 
              onPress: () => navigation.navigate('SpecialGuest')
            }
          ]
        );
      }
    },
  ];

  if (loading) {
    return (
      <View style={styles.loadingContainer}>
        <Text style={styles.loadingText}>Loading profile...</Text>
      </View>
    );
  }

  return (
    <View style={[styles.container, { backgroundColor: theme.bg }]}>
      <StatusBar barStyle={theme.statusBar} backgroundColor={theme.headerBg} />
      
      {/* Header */}
      <LinearGradient
        colors={['#667eea', '#764ba2']}
        style={styles.header}
      >
        <SafeAreaView style={styles.safeArea}>
          <View style={styles.headerContent}>
            <TouchableOpacity 
              style={styles.backButton}
              onPress={() => navigation.goBack()}
            >
              <Ionicons name="arrow-back" size={24} color="white" />
            </TouchableOpacity>
            
            <Text style={styles.headerTitle}>My Profile</Text>
            
            <TouchableOpacity 
              style={styles.editButton}
              onPress={() => navigation.navigate('EditProfile')}
            >
              <Ionicons name="create-outline" size={24} color="white" />
            </TouchableOpacity>
          </View>
        </SafeAreaView>
      </LinearGradient>

      <ScrollView style={styles.scrollContainer} showsVerticalScrollIndicator={false}>
        {/* Profile Card */}
        <View style={styles.profileCard}>
          <View style={styles.avatarContainer}>
            {user?.avatar ? (
              <Image source={{ uri: user.avatar }} style={styles.avatar} />
            ) : (
              <LinearGradient
                colors={['#FF6B6B', '#4ECDC4']}
                style={styles.avatarGradient}
              >
                <Text style={styles.avatarText}>
                  {user?.name?.charAt(0)?.toUpperCase() || 'U'}
                </Text>
              </LinearGradient>
            )}
            <TouchableOpacity style={styles.cameraButton}>
              <Ionicons name="camera" size={16} color="white" />
            </TouchableOpacity>
          </View>
          
          <Text style={styles.userName}>{user?.name || 'User'}</Text>
          <Text style={styles.userEmail}>{user?.email || 'user@example.com'}</Text>
          
          <View style={styles.statsContainer}>
            <View style={styles.statItem}>
              <Text style={styles.statNumber}>{user?.totalOrders || 0}</Text>
              <Text style={styles.statLabel}>Orders</Text>
            </View>
            <View style={styles.statDivider} />
            <View style={styles.statItem}>
              <Text style={styles.statNumber}>
                UGX {(user?.totalSpent || 0).toLocaleString()}
              </Text>
              <Text style={styles.statLabel}>Total Spent</Text>
            </View>
          </View>
        </View>

        {/* Menu Items */}
        <View style={styles.menuSection}>
          {menuItems.map((item) => (
            <TouchableOpacity
              key={item.id}
              style={styles.menuItem}
              onPress={item.onPress}
            >
              <View style={[styles.menuIcon, { backgroundColor: item.color + '20' }]}>
                <Ionicons name={item.icon} size={24} color={item.color} />
              </View>
              <View style={styles.menuContent}>
                <Text style={styles.menuTitle}>{item.title}</Text>
                <Text style={styles.menuSubtitle}>{item.subtitle}</Text>
              </View>
              <Ionicons name="chevron-forward" size={20} color="#bdc3c7" />
            </TouchableOpacity>
          ))}
        </View>

        {/* Settings Section */}
        <View style={styles.settingsSection}>
          <Text style={styles.sectionTitle}>Settings</Text>
          
          <View style={styles.settingItem}>
            <View style={styles.settingLeft}>
              <View style={[styles.settingIcon, { backgroundColor: '#3498db20' }]}>
                <Ionicons name="notifications-outline" size={20} color="#3498db" />
              </View>
              <View>
                <Text style={styles.settingTitle}>Push Notifications</Text>
                <Text style={styles.settingSubtitle}>Get notified about orders</Text>
              </View>
            </View>
            <Switch
              value={notifications}
              onValueChange={setNotifications}
              trackColor={{ false: '#e0e0e0', true: '#667eea' }}
              thumbColor={notifications ? '#ffffff' : '#f4f3f4'}
            />
          </View>

          <View style={styles.settingItem}>
            <View style={styles.settingLeft}>
              <View style={[styles.settingIcon, { backgroundColor: '#e74c3c20' }]}>
                <Ionicons name="mail-outline" size={20} color="#e74c3c" />
              </View>
              <View>
                <Text style={styles.settingTitle}>Email Updates</Text>
                <Text style={styles.settingSubtitle}>Receive promotional emails</Text>
              </View>
            </View>
            <Switch
              value={emailUpdates}
              onValueChange={setEmailUpdates}
              trackColor={{ false: '#e0e0e0', true: '#667eea' }}
              thumbColor={emailUpdates ? '#ffffff' : '#f4f3f4'}
            />
          </View>

          <View style={styles.settingItem}>
            <View style={styles.settingLeft}>
              <View style={[styles.settingIcon, { backgroundColor: '#34495e20' }]}>
                <Ionicons name="moon-outline" size={20} color="#34495e" />
              </View>
              <View>
                <Text style={styles.settingTitle}>Dark Mode</Text>
                <Text style={styles.settingSubtitle}>{isDark ? 'Dark theme active' : 'Light theme active'}</Text>
              </View>
            </View>
            <Switch
              value={isDark}
              onValueChange={toggleTheme}
              trackColor={{ false: '#e0e0e0', true: '#3498db' }}
              thumbColor={isDark ? '#ffffff' : '#f4f3f4'}
            />
          </View>
        </View>

        {/* Logout Button */}
        <View style={styles.logoutSection}>
          <TouchableOpacity style={styles.logoutButton} onPress={handleLogout}>
            <Ionicons name="log-out-outline" size={20} color="#e74c3c" />
            <Text style={styles.logoutText}>Logout</Text>
          </TouchableOpacity>
        </View>

        <View style={styles.bottomSpacing} />
      </ScrollView>

      {/* Toast Component */}
      <Toast 
        config={{
          success: (props) => <CustomToast {...props} type="success" />,
          error: (props) => <CustomToast {...props} type="error" />,
          info: (props) => <CustomToast {...props} type="info" />,
          warning: (props) => <CustomToast {...props} type="warning" />,
        }}
      />
    </View>
  );
};

